INSERT INTO reviews (id, city_name, nickname, rating, content, hashtags, coworking_id, date) VALUES
('r1', '서울', 'CodeNomad_K', 5, '성수동 카페에서 작업하는 느낌이 정말 좋아요. 기가비트 와이파이에 노트북 충전 포트도 넉넉하고, 주변에 맛집도 많아서 점심 걱정이 없네요. 한 달 살기 강력 추천합니다!', ARRAY['#성수동','#카페작업','#기가와이파이'], 'cw1', '2026.03.10'),
('r2', '제주', 'IslandWorker', 5, '제주에서 3개월 살았는데 인생 최고의 경험이었어요. 애월 카페에서 바다 보면서 코딩하다 보면 시간 가는 줄 모르고, 퇴근 후엔 한라산 트레킹. 번아웃 완전 해소됐습니다.', ARRAY['#제주살이','#애월카페','#워케이션'], 'cw8', '2026.03.05'),
('r3', '부산', 'RemoteDevBusan', 4, '해운대 근처 코워킹 스페이스 가격 대비 퀄리티 최고예요. 서울보다 훨씬 여유롭고 바다 산책도 가능해서 스트레스 관리에 좋습니다. 다만 글로벌 밋업은 서울보다 적은 편.', ARRAY['#해운대','#코워킹','#부산노마드'], 'cw4', '2026.02.28'),
('r4', '서울', 'SeoulCoder99', 5, '강남 코워킹에서 미팅 후 테헤란로 걷기. 스타트업 에너지가 넘치는 도시예요. 곳곳에 개발자 컨퍼런스와 네트워킹 행사가 열려서 자극도 많이 받고 인맥도 쌓을 수 있어요.', ARRAY['#강남','#테헤란로','#스타트업'], 'cw2', '2026.03.08'),
('r5', '서울', 'NomadMom', 4, '아이 동반 노마드로 홍대 카페 투어 즐겼어요. 심야카페도 많고 분위기 다양해서 좋아요. 어린이 친화적인 공간도 꽤 있어서 가족 노마드에게도 추천합니다.', ARRAY['#홍대','#카페투어','#서울노마드'], NULL, '2026.03.01'),
('r6', '부산', 'SurfDev', 5, '광안리 야경 보면서 코딩, 인생샷 찍고 퇴근. 부산이 이렇게 좋은 도시인지 몰랐어요. 서울에서 KTX 타면 2시간 반이라 이동도 부담 없고 주말 여행지로도 완벽해요.', ARRAY['#광안리','#야경','#부산살이'], NULL, '2026.02.20'),
('r7', '제주', 'MorningHiker', 5, '한달살이 두 번째 방문. 서귀포 감귤밭 옆 카페에서 재택. 힐링 완료했습니다. 오전에 오름 트레킹하고 오후에 코딩하면 하루가 너무 알차요. 공기도 맑고 스트레스가 없어요.', ARRAY['#서귀포','#감귤','#제주한달살이'], 'cw9', '2026.02.15'),
('r8', '대구', 'TechDaegu', 4, '수성구 코워킹 스페이스 가격 대비 최고예요. 서울보다 훨씬 조용하고 집중 잘 돼요. 대구 스타트업 씬이 생각보다 활발해서 놀랐고, 지역 개발자 커뮤니티도 따뜻하게 맞아줬어요.', ARRAY['#수성구','#대구노마드','#집중'], NULL, '2026.03.05'),
('r9', '인천', 'SongdoWorker', 4, '송도에서 3주 거주. 공원 산책하며 미팅하고 카페서 코딩. 국제도시 바이브가 좋아요. 센트럴파크 옆 카페에서 작업하면 마치 해외 도시에 있는 것 같은 느낌이 나요.', ARRAY['#송도','#인천노마드','#공원'], NULL, '2026.02.25'),
('r10', '대전', 'KaistNeighbor', 5, '유성구 카페에서 연구자들과 네트워킹. 기술 이야기가 끊이질 않는 도시예요. KAIST, ETRI 연구원들과 자연스럽게 어울릴 수 있어서 기술적 영감을 받기에 최고의 환경입니다.', ARRAY['#유성구','#대전','#테크노마드'], NULL, '2026.03.12');
INSERT INTO meetups (id, title, date, city, rsvp_count, description, category, max_attendees, organizer, tags) VALUES
('m1', '서울 노마드 네트워킹 나잇', '3월 20일 (목) 19:00', '서울', 34, '서울 성수동에서 열리는 디지털 노마드 네트워킹 행사입니다. 프리랜서, 원격근무자, 스타트업 창업자들이 모여 경험을 나누고 인맥을 쌓는 자리입니다.', '네트워킹', 50, 'CodeNomad_K', ARRAY['네트워킹','성수동','프리랜서']),
('m2', '제주 코더스 위클리 밋업', '3월 22일 (토) 14:00', '제주', 18, '제주에서 활동하는 개발자들의 주간 모임입니다. 각자의 사이드 프로젝트를 공유하고 기술 이야기를 나누는 캐주얼한 자리입니다.', '스터디', 25, 'IslandWorker', ARRAY['개발','제주','사이드프로젝트']),
('m3', '부산 리모트워크 커피챗', '3월 25일 (화) 10:00', '부산', 12, '해운대 바다 뷰 카페에서 진행하는 리모트워커들의 커피챗입니다. 원격근무 팁과 생산성 노하우를 자유롭게 공유하는 소규모 모임이에요.', '소셜', 20, 'RemoteDevBusan', ARRAY['리모트워크','해운대','커피챗']),
('m4', '서울 프리랜서 세금 스터디', '3월 27일 (목) 19:30', '서울', 27, '프리랜서와 1인 사업자를 위한 세금 스터디입니다. 종합소득세 신고, 부가가치세, 경비 처리 방법 등 실질적인 세무 지식을 함께 공부합니다.', '스터디', 40, 'SeoulCoder99', ARRAY['세금','프리랜서','재테크']),
('m5', '제주 선셋 요가 & 네트워킹', '3월 29일 (토) 17:00', '제주', 21, '제주 협재 해변에서 진행하는 선셋 요가와 네트워킹 행사입니다. 요가 세션 후 자연스럽게 네트워킹하는 힐링 밋업입니다.', '소셜', 30, 'JejuDesigner', ARRAY['요가','협재해변','힐링']),
('m6', '대구 노마드 첫 밋업', '4월 3일 (목) 19:00', '대구', 9, '대구 디지털 노마드 커뮤니티의 첫 번째 공식 밋업입니다. 대구에서 활동하는 원격근무자, 프리랜서, 창업자들이 처음으로 한 자리에 모입니다.', '네트워킹', 30, 'TechDaegu', ARRAY['대구','첫밋업','커뮤니티']),
('m7', '인천 송도 조식 네트워킹', '4월 5일 (토) 09:00', '인천', 15, '송도 센트럴파크 인근에서 진행하는 조식 네트워킹입니다. 아침 식사를 함께하며 가볍게 대화를 나누는 편안한 모임입니다.', '네트워킹', 25, 'SongdoWorker', ARRAY['송도','조식','공원']),
('m8', '광주 문화노마드 투어', '4월 8일 (화) 14:00', '광주', 11, '광주 문화예술의 도시를 함께 탐방하는 노마드 투어입니다. 국립아시아문화전당, 충장로 예술 거리를 함께 걷고 작업하기 좋은 카페와 공간을 소개합니다.', '소셜', 20, 'NomadMom', ARRAY['광주','문화투어','예술']),
('m9', '대전 사이드프로젝트 발표회', '4월 10일 (목) 19:30', '대전', 22, '대전 개발자와 디자이너들의 사이드 프로젝트 발표 행사입니다. 5분 라이트닝 토크 형식으로 진행되며 피드백과 협업 기회를 찾을 수 있습니다.', '워크숍', 35, 'KaistNeighbor', ARRAY['사이드프로젝트','발표','개발']),
('m10', '부산 해운대 선셋 런닝', '4월 12일 (토) 17:30', '부산', 19, '해운대 해변을 따라 달리는 선셋 런닝 모임입니다. 약 5km 코스로 편하게 달리고 이후 해변 카페에서 네트워킹합니다.', '소셜', 30, 'SurfDev', ARRAY['런닝','해운대','운동']),
('m11', '서울 UX/UI 디자인 워크숍', '4월 15일 (화) 14:00', '서울', 16, '피그마를 활용한 실전 UX/UI 디자인 워크숍입니다. 노마드 플랫폼 디자인을 주제로 함께 작업하며 피드백을 주고받습니다.', '워크숍', 20, 'SeoulCoder99', ARRAY['UX','피그마','디자인']),
('m12', '제주 영어 스터디 & 네트워킹', '4월 17일 (목) 18:00', '제주', 14, '제주 노마드들을 위한 영어 스터디 겸 네트워킹 모임입니다. 영어 프레젠테이션 연습과 외국인 노마드와의 교류를 목적으로 합니다.', '스터디', 20, 'IslandWorker', ARRAY['영어','스터디','외국인']),
('m13', '부산 프리랜서 포트폴리오 리뷰', '4월 19일 (토) 13:00', '부산', 10, '프리랜서 개발자와 디자이너를 위한 포트폴리오 상호 리뷰 세션입니다. 서로의 작업물을 솔직하게 피드백하고 더 나은 포트폴리오를 만들 수 있도록 도와줍니다.', '워크숍', 15, 'RemoteDevBusan', ARRAY['포트폴리오','프리랜서','피드백']),
('m14', '서울 스타트업 창업 스터디', '4월 22일 (화) 19:00', '서울', 31, '스타트업 창업을 꿈꾸는 노마드들의 스터디 모임입니다. 비즈니스 모델, 투자 유치, MVP 개발 등 창업 전반에 걸친 내용을 함께 공부합니다.', '스터디', 40, 'CodeNomad_K', ARRAY['창업','스타트업','멘토링']),
('m15', '대전 AI 개발자 밋업', '4월 24일 (목) 19:00', '대전', 25, '대전 KAIST, ETRI 인근의 AI 개발자와 연구자들이 모이는 밋업입니다. 최신 AI 트렌드와 실제 프로젝트 사례를 공유하고 협업 기회를 찾습니다.', '네트워킹', 40, 'KaistNeighbor', ARRAY['AI','개발','연구']);
